Here are both approaches using Shell navigation and `IQueryAttributable`:

**1. The Model**

```csharp
public class Product
{
    public string Id { get; set; }
    public string Name { get; set; }
    public decimal Price { get; set; }
}
```

**2. Navigating (from ProductListPage)**

```csharp
// Approach A – pass just the ID as a string query parameter
await Shell.Current.GoToAsync($"{nameof(ProductDetailsPage)}?productId={product.Id}");

// Approach B – pass the full object via a dictionary
await Shell.Current.GoToAsync(nameof(ProductDetailsPage),
    new Dictionary<string, object>
    {
        ["product"] = product   // complex object, not serialized into the URI
    });
```

**3. Receiving (ViewModel implements `IQueryAttributable`)**

```csharp
public class ProductDetailsViewModel : ObservableObject, IQueryAttributable
{
    private Product _product;
    public Product Product
    {
        get => _product;
        set => SetProperty(ref _product, value);
    }

    public void ApplyQueryAttributes(IDictionary<string, object> query)
    {
        // Approach B – full object passed via dictionary
        if (query.TryGetValue("product", out var obj) && obj is Product p)
        {
            Product = p;
        }
        // Approach A – only the ID was passed as a string
        else if (query.TryGetValue("productId", out var idObj))
        {
            var id = idObj.ToString();
            LoadProductAsync(id).FireAndForget();
        }
    }

    private async Task LoadProductAsync(string id)
    {
        Product = await SomeService.GetProductByIdAsync(id);
    }
}
```

**4. Wire the ViewModel to the Page**

```csharp
public partial class ProductDetailsPage : ContentPage
{
    public ProductDetailsPage(ProductDetailsViewModel vm)
    {
        InitializeComponent();
        BindingContext = vm;  // Shell resolves IQueryAttributable from BindingContext
    }
}
```

**5. Register route + DI**

```csharp
// In MauiProgram.cs or AppShell
Routing.RegisterRoute(nameof(ProductDetailsPage), typeof(ProductDetailsPage));

// In service registration
builder.Services.AddTransient<ProductDetailsPage>();
builder.Services.AddTransient<ProductDetailsViewModel>();
```

**Key differences:**

| | String query param | Dictionary object |
|---|---|---|
| **Syntax** | embedded in URI | `Dictionary<string, object>` overload |
| **Type in `ApplyQueryAttributes`** | arrives as `string` | arrives as the original `object` |
| **Use when** | simple/primitive values | complex objects already in memory |

Shell calls `ApplyQueryAttributes` on the page's `BindingContext` automatically — no attributes or extra wiring needed beyond implementing `IQueryAttributable`.
